import React from 'react';

function ResumeCard({ resume }) {

  return (

    <div className="card shadow p-4 mb-4">

      <h3>{resume.fullName}</h3>

      <p>{resume.email}</p>

      <p>{resume.phone}</p>

      <hr />

      <h5>Skills</h5>

      <p>{resume.skills}</p>

      <h5>Education</h5>

      <p>{resume.education}</p>

      <h5>Experience</h5>

      <p>{resume.experience}</p>

    </div>
  );
}

export default ResumeCard;
